306	              <tr>
307	                <th className="p-4 w-12"><Checkbox checked={eventsData?.events?.length > 0 && selectedIds.length === eventsData?.events?.length} onCheckedChange={toggleAll} /></th>
308	                <th className="p-4 min-w-[250px]">
309	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("title")}>Titolo <SortIcon col="title" /></button>
310	                </th>
311	                <th className="p-4">
312	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("date")}>Data <SortIcon col="date" /></button>
313	                </th>
314	                <th className="p-4">
315	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("location")}>Luogo <SortIcon col="location" /></button>
