330	                <tr><td colSpan={7} className="p-12 text-center text-muted-foreground">Nessun evento trovato.</td></tr>
331	              ) : (
332	                sortedEvents.map(event => (
333	                  <tr key={event.id} className="hover:bg-muted/10 transition-colors group">
334	                    <td className="p-4"><Checkbox checked={selectedIds.includes(event.id)} onCheckedChange={() => toggleOne(event.id)} /></td>
335	                    <td className="p-4 min-w-[250px]">
336	                      <div className="font-medium text-foreground text-base">{event.title}</div>
337	                    </td>
338	                    <td className="p-4 text-muted-foreground text-xs whitespace-nowrap">
339	                      <div className="flex items-center gap-2">
340	                        <Clock className="w-3 h-3 shrink-0" />
341	                        {event.dateDisplay || (event.dateStart ? format(new Date(event.dateStart), 'dd MMM yyyy', { locale: it }) : 'Sconosciuta')}
342	                        {event.dateParseConfidence === 'low' && (
343	                          <AlertTriangle className="w-3 h-3 text-amber-500" title="Data parsing a bassa confidenza" />
344	                        )}
345	                      </div>
346	                    </td>
347	                    <td className="p-4 text-muted-foreground">
348	                      {event.location ? (
349	                        <div className="flex items-center gap-1.5 truncate max-w-[200px]">
350	                          <MapPin className="w-3.5 h-3.5 shrink-0" />
351	                          <span className="truncate">{event.location}</span>
352	                        </div>
353	                      ) : '-'}
354	                    </td>
355	                    <td className="p-4">
356	                      <div className="flex flex-col gap-1 items-start">
357	                        <span className="text-xs truncate max-w-[150px]">{event.sourceName || 'Manuale'}</span>
358	                        <Badge variant="outline" className={`text-[10px] uppercase tracking-wider ${event.sourceType === 'manual' ? 'text-purple-600 border-purple-200' : 'text-blue-600 border-blue-200'}`}>
359	                          {event.sourceType}
360	                        </Badge>
361	                      </div>
362	                    </td>
363	                    <td className="p-4">{getStatusBadge(event.status)}</td>
364	                    <td className="p-4 text-right">
365	                      <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-primary">
366	                        <Eye className="w-4 h-4" />
367	                      </Button>
368	                    </td>
369	                  </tr>
370	                ))
371	              )}
372	            </tbody>
373	          </table>
374	        </div>
375	      </div>
376	    </AppLayout>
