import { useState } from "react";
import { AppLayout } from "@/components/layout";
import { useListEvents, useBulkUpdateEvents, useDeleteEvent, useListSources, useCreateEvent, useUpdateEvent } from "@workspace/api-client-react";
import type { UpdateEventRequest, Event as ApiEvent } from "@workspace/api-client-react/src/generated/api.schemas";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { format } from "date-fns";
import { it } from "date-fns/locale";
import { Search, Plus, AlertTriangle, CheckCircle2, XCircle, MapPin, Clock, Pencil, ChevronUp, ChevronDown, ChevronsUpDown } from "lucide-react";
import { useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/components/ui/use-toast";

export default function Eventi() {
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [sourceFilter, setSourceFilter] = useState<string>("all");
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedIds, setSelectedIds] = useState<number[]>([]);
  const [sortCol, setSortCol] = useState<string | null>(null);
  const [sortDir, setSortDir] = useState<"asc" | "desc">("asc");

  const { data: eventsData, isLoading } = useListEvents({
    status: statusFilter !== "all" ? statusFilter : undefined,
    sourceId: sourceFilter !== "all" ? Number(sourceFilter) : undefined,
    search: searchTerm || undefined,
    limit: 50,
  });

  const { data: sources } = useListSources();
  const bulkMutation = useBulkUpdateEvents();
  const deleteMutation = useDeleteEvent();
  const createMutation = useCreateEvent();
  const updateMutation = useUpdateEvent();
  const queryClient = useQueryClient();
  const { toast } = useToast();

  const [addOpen, setAddOpen] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newDateStart, setNewDateStart] = useState("");
  const [newDateEnd, setNewDateEnd] = useState("");
  const [newLocation, setNewLocation] = useState("");
  const [newDescription, setNewDescription] = useState("");
  const [newPrice, setNewPrice] = useState("");
  const [newUrl, setNewUrl] = useState("");
  const [isSaving, setIsSaving] = useState(false);

  const [editingEvent, setEditingEvent] = useState<ApiEvent | null>(null);
  const [editForm, setEditForm] = useState<UpdateEventRequest>({});

  const openEdit = (event: ApiEvent) => {
    setEditingEvent(event);
    setEditForm({
      title: event.title,
      dateStart: event.dateStart ?? null,
      dateEnd: event.dateEnd ?? null,
      dateDisplay: event.dateDisplay ?? null,
      location: event.location ?? null,
      descriptionRaw: event.descriptionRaw ?? null,
      price: event.price ?? null,
      sourceUrl: event.sourceUrl ?? null,
      status: event.status,
    });
  };

  const handleUpdate = async () => {
    if (!editingEvent) return;
    if (!editForm.title?.trim()) {
      toast({ title: "Il titolo è obbligatorio", variant: "destructive" });
      return;
    }
    setIsSaving(true);
    try {
      await updateMutation.mutateAsync({ id: editingEvent.id, data: editForm });
      toast({ title: "Evento aggiornato" });
      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
      setEditingEvent(null);
    } catch {
      toast({ title: "Errore nell'aggiornamento", variant: "destructive" });
    } finally {
      setIsSaving(false);
    }
  };

  const openAdd = () => {
    setNewTitle(""); setNewDateStart(""); setNewDateEnd("");
    setNewLocation(""); setNewDescription(""); setNewPrice(""); setNewUrl("");
    setAddOpen(true);
  };

  const handleCreate = async () => {
    if (!newTitle.trim()) {
      toast({ title: "Il titolo è obbligatorio", variant: "destructive" });
      return;
    }
    setIsSaving(true);
    try {
      await createMutation.mutateAsync({
        data: {
          title: newTitle,
          dateStart: newDateStart || null,
          dateEnd: newDateEnd || null,
          location: newLocation || null,
          descriptionRaw: newDescription || null,
          price: newPrice || null,
          sourceUrl: newUrl || null,
          sourceType: "manual",
          status: "pending",
        },
      });
      toast({ title: "Evento creato" });
      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
      setAddOpen(false);
    } catch {
      toast({ title: "Errore nella creazione", variant: "destructive" });
    } finally {
      setIsSaving(false);
    }
  };

  const handleBulkAction = async (action: string) => {
    if (selectedIds.length === 0) return;
    try {
      await bulkMutation.mutateAsync({ data: { ids: selectedIds, action } });
      toast({ title: "Eventi aggiornati" });
      setSelectedIds([]);
      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
    } catch (e) {
      toast({ title: "Errore", variant: "destructive" });
    }
  };

  const toggleAll = (checked: boolean) => {
    if (checked && eventsData) setSelectedIds(eventsData.events.map(e => e.id));
    else setSelectedIds([]);
  };

  const toggleOne = (id: number) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'pending': return <Badge className="bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-100">In attesa</Badge>;
      case 'approved': return <Badge className="bg-green-100 text-green-700 border-green-200 hover:bg-green-100">Approvato</Badge>;
      case 'rejected': return <Badge className="bg-red-100 text-red-700 border-red-200 hover:bg-red-100">Rifiutato</Badge>;
      default: return <Badge variant="outline">{status}</Badge>;
    }
  };

  const handleSort = (col: string) => {
    if (sortCol === col) setSortDir(d => d === "asc" ? "desc" : "asc");
    else { setSortCol(col); setSortDir("asc"); }
  };

  const sortedEvents = [...(eventsData?.events ?? [])].sort((a, b) => {
    if (!sortCol) return 0;
    let av: string, bv: string;
    if (sortCol === "date") {
      av = a.dateStart ?? "";
      bv = b.dateStart ?? "";
    } else if (sortCol === "source") {
      av = (a.sourceName ?? "Manuale").toLowerCase();
      bv = (b.sourceName ?? "Manuale").toLowerCase();
    } else if (sortCol === "status") {
      av = a.status;
      bv = b.status;
    } else if (sortCol === "title") {
      av = a.title.toLowerCase();
      bv = b.title.toLowerCase();
    } else if (sortCol === "location") {
      av = (a.location ?? "").toLowerCase();
      bv = (b.location ?? "").toLowerCase();
    } else return 0;
    if (av < bv) return sortDir === "asc" ? -1 : 1;
    if (av > bv) return sortDir === "asc" ? 1 : -1;
    return 0;
  });

  const SortIcon = ({ col }: { col: string }) => {
    if (sortCol !== col) return <ChevronsUpDown className="w-3.5 h-3.5 ml-1 opacity-40" />;
    return sortDir === "asc"
      ? <ChevronUp className="w-3.5 h-3.5 ml-1" />
      : <ChevronDown className="w-3.5 h-3.5 ml-1" />;
  };

  return (
    <AppLayout>
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-3xl font-bold font-display text-foreground tracking-tight">Eventi</h1>
          <p className="text-muted-foreground mt-1">Gestisci, revisiona e approva gli eventi per la newsletter.</p>
        </div>
        <Button className="shadow-md" onClick={openAdd}>
          <Plus className="w-4 h-4 mr-2" />
          Aggiungi Evento
        </Button>
      </div>

      <Dialog open={addOpen} onOpenChange={setAddOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Nuovo Evento</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label htmlFor="ev-title">Titolo *</Label>
              <Input id="ev-title" value={newTitle} onChange={e => setNewTitle(e.target.value)} placeholder="Es. Mercato di Natale in Piazza" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="ev-start">Data inizio</Label>
                <Input id="ev-start" type="date" value={newDateStart} onChange={e => setNewDateStart(e.target.value)} />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="ev-end">Data fine</Label>
                <Input id="ev-end" type="date" value={newDateEnd} onChange={e => setNewDateEnd(e.target.value)} />
              </div>
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="ev-location">Luogo</Label>
              <Input id="ev-location" value={newLocation} onChange={e => setNewLocation(e.target.value)} placeholder="Es. Piazza Repubblica, Varese" />
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="ev-desc">Descrizione</Label>
              <Textarea id="ev-desc" value={newDescription} onChange={e => setNewDescription(e.target.value)} placeholder="Breve descrizione dell'evento..." rows={3} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="ev-price">Prezzo</Label>
                <Input id="ev-price" value={newPrice} onChange={e => setNewPrice(e.target.value)} placeholder="Es. Gratuito / €10" />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="ev-url">URL</Label>
                <Input id="ev-url" type="url" value={newUrl} onChange={e => setNewUrl(e.target.value)} placeholder="https://..." />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setAddOpen(false)} disabled={isSaving}>Annulla</Button>
            <Button onClick={handleCreate} disabled={isSaving}>
              {isSaving ? "Salvataggio..." : "Crea Evento"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <div className="bg-card p-4 rounded-xl border border-border/50 mb-6 flex flex-col md:flex-row gap-4 shadow-sm">
        <div className="flex-1 relative">
          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input 
            placeholder="Cerca evento..." 
            className="pl-9 bg-background"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex flex-wrap gap-3">
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[140px] bg-background">
              <SelectValue placeholder="Stato" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Tutti gli stati</SelectItem>
              <SelectItem value="pending">In attesa</SelectItem>
              <SelectItem value="approved">Approvati</SelectItem>
              <SelectItem value="rejected">Rifiutati</SelectItem>
            </SelectContent>
          </Select>

          <Select value={sourceFilter} onValueChange={setSourceFilter}>
            <SelectTrigger className="w-[180px] bg-background">
              <SelectValue placeholder="Tutte le fonti" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Tutte le fonti</SelectItem>
              {sources?.map(s => <SelectItem key={s.id} value={s.id.toString()}>{s.name}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>
      </div>

      {selectedIds.length > 0 && (
        <div className="bg-primary/5 border border-primary/20 p-3 rounded-lg mb-4 flex items-center justify-between animate-in fade-in slide-in-from-top-2">
          <span className="text-sm font-medium text-primary ml-2">{selectedIds.length} eventi selezionati</span>
          <div className="flex gap-2">
            <Button size="sm" variant="outline" className="border-green-200 text-green-700 hover:bg-green-50" onClick={() => handleBulkAction('approve')}>
              <CheckCircle2 className="w-4 h-4 mr-1" /> Approva
            </Button>
            <Button size="sm" variant="outline" className="border-red-200 text-red-700 hover:bg-red-50" onClick={() => handleBulkAction('reject')}>
              <XCircle className="w-4 h-4 mr-1" /> Rifiuta
            </Button>
          </div>
        </div>
      )}

      <div className="bg-card rounded-xl border border-border/50 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-muted/30 text-muted-foreground font-medium border-b border-border/50">
              <tr>
                <th className="p-4 w-12"><Checkbox checked={eventsData?.events?.length > 0 && selectedIds.length === eventsData?.events?.length} onCheckedChange={toggleAll} /></th>
                <th className="p-4 min-w-[250px]">
                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("title")}>Titolo <SortIcon col="title" /></button>
                </th>
                <th className="p-4">
                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("date")}>Data <SortIcon col="date" /></button>
                </th>
                <th className="p-4">
                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("location")}>Luogo <SortIcon col="location" /></button>
                </th>
                <th className="p-4">
                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("source")}>Fonte <SortIcon col="source" /></button>
                </th>
                <th className="p-4">
                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("status")}>Stato <SortIcon col="status" /></button>
                </th>
                <th className="p-4 text-right">Azioni</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border/30">
              {isLoading ? (
                <tr><td colSpan={7} className="p-8 text-center text-muted-foreground animate-pulse">Caricamento...</td></tr>
              ) : sortedEvents.length === 0 ? (
                <tr><td colSpan={7} className="p-12 text-center text-muted-foreground">Nessun evento trovato.</td></tr>
              ) : (
                sortedEvents.map(event => (
                  <tr key={event.id} className="hover:bg-muted/10 transition-colors group">
                    <td className="p-4"><Checkbox checked={selectedIds.includes(event.id)} onCheckedChange={() => toggleOne(event.id)} /></td>
                    <td className="p-4 min-w-[250px]">
                      <div className="font-medium text-foreground text-base">{event.title}</div>
                    </td>
                    <td className="p-4 text-muted-foreground text-xs whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        <Clock className="w-3 h-3 shrink-0" />
                        {event.dateDisplay || (event.dateStart ? format(new Date(event.dateStart), 'dd MMM yyyy', { locale: it }) : 'Sconosciuta')}
                        {event.dateParseConfidence === 'low' && (
                          <AlertTriangle className="w-3 h-3 text-amber-500" title="Data parsing a bassa confidenza" />
                        )}
                      </div>
                    </td>
                    <td className="p-4 text-muted-foreground">
                      {event.location ? (
                        <div className="flex items-center gap-1.5 truncate max-w-[200px]">
                          <MapPin className="w-3.5 h-3.5 shrink-0" />
                          <span className="truncate">{event.location}</span>
                        </div>
                      ) : '-'}
                    </td>
                    <td className="p-4">
                      <div className="flex flex-col gap-1 items-start">
                        <span className="text-xs truncate max-w-[150px]">{event.sourceName || 'Manuale'}</span>
                        <Badge variant="outline" className={`text-[10px] uppercase tracking-wider ${event.sourceType === 'manual' ? 'text-purple-600 border-purple-200' : 'text-blue-600 border-blue-200'}`}>
                          {event.sourceType}
                        </Badge>
                      </div>
                    </td>
                    <td className="p-4">{getStatusBadge(event.status)}</td>
                    <td className="p-4 text-right">
                      <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-primary">
                        <Eye className="w-4 h-4" />
                      </Button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </AppLayout>
  );
}

