          location: raw.location || existing.location,
          price: raw.price || existing.price,
          category: raw.category || existing.category,
          imageUrl: raw.image_url || existing.imageUrl,
          updatedAt: new Date(),
        }).where(eq(eventsTable.id, existing.id));
        saved++;
